{"code": "import json
import re
import pandas as pd

# Read German patents data
file_path = locals()['var_functions.query_db:28']
with open(file_path, 'r') as f:
    german_patents = json.load(f)

def extract_cpc_main_group(cpc_code):
    """Extract main group from CPC code (first part before slash)"""
    if not cpc_code:
        return None
    cpc_code = cpc_code.strip()
    if '/' in cpc_code:
        return cpc_code.split('/')[0]
    return cpc_code

# Process patents for time series analysis
month_map = {
    'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6,
    'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12
}

# Collect data by year and CPC main group
cpc_data = []

for patent in german_patents:
    patents_info = patent.get('Patents_info', '')
    grant_date = patent.get('grant_date', '')
    cpc = patent.get('cpc', '[]')
    title_localized = patent.get('title_localized', '[]')

    if not grant_date or not ('DE-' in patents_info):
        continue

    # Extract year and month
    year_match = re.search(r'(20\d{2})', grant_date)
    if not year_match:
        continue

    year = int(year_match.group(1))

    month = None
    grant_date_lower = grant_date.lower()
    for month_name, month_num in month_map.items():
        if month_name in grant_date_lower:
            month = month_num
            break

    if not month:
        continue

    # Extract title
    title = ""
    try:
        title_list = json.loads(title_localized) if isinstance(title_localized, str) else title_localized
        if title_list and len(title_list) > 0:
            for lang_pref in ['de', 'en']:
                for t in title_list:
                    if t.get('language') == lang_pref and t.get('text'):
                        title = t.get('text')
                        break
                if title:
                    break
            if not title and title_list[0].get('text'):
                title = title_list[0].get('text')
    except:
        pass

    # Extract CPC codes
    try:
        cpc_list = json.loads(cpc) if isinstance(cpc, str) else cpc
        if not isinstance(cpc_list, list):
            cpc_list = []
    except:
        cpc_list = []

    cpc_codes = [item.get('code') for item in cpc_list if isinstance(item, dict) and item.get('code')]

    for cpc_code in cpc_codes:
        main_group = extract_cpc_main_group(cpc_code)
        if main_group:
            cpc_data.append({
                'year': year,
                'month': month,
                'cpc_main_group': main_group,
                'title': title,
                'patent_id': patents_info
            })

# Create DataFrame
df = pd.DataFrame(cpc_data)

# Filter for second half of 2019 and get all data for EMA calculation
df_2019_h2 = df[(df['year'] == 2019) & (df['month'] >= 7)]

# Group by CPC main group and count patents per year
df_yearly = df.groupby(['year', 'cpc_main_group']).size().reset_index(name='count')

# Get available years for EMA calculation
available_years = sorted(df_yearly['year'].unique())

print('__RESULT__:')
print(json.dumps({
    'data_points': len(cpc_data),
    'available_years': available_years,
    'cpc_groups_in_h2_2019': df_2019_h2['cpc_main_group'].nunique(),
