    cpc_definitions = json.load(f)

# Create CPC level 4 titles lookup
cpc_level4_titles = {item['symbol']: item['titleFull'] for item in cpc_definitions}

# Extract CPC level 4 from full code
def extract_cpc_level4(cpc_code):
    """Extract level 4 CPC (class level, e.g., C04B, H04W, F02D)"""
    if not cpc_code:
        return None
    cpc_code = cpc_code.strip()
    # Pattern: Section (A-H,Y) + Class (2 digits) + Subclass (1 letter)
    # This gives us level 4 (class) CPC codes
    match = re.match(r'^([A-Z][0-9]{2}[A-Z])', cpc_code)
    if match:
        return match.group(1)
    return None

# Extract year and month
month_map = {
    'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6,
    'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12
}

def extract_year_month(grant_date):
    """Extract year and month from grant date"""
    year_match = re.search(r'(20\d{2})', grant_date)
    if not year_match:
        return None, None

    year = int(year_match.group(1))

    month = None
    grant_date_lower = grant_date.lower()
    for month_name, month_num in month_map.items():
        if month_name in grant_date_lower:
            month = month_num
            break

    return year, month

# Collect data
cpc_yearly_counts = defaultdict(lambda: defaultdict(int))  # {cpc_level4: {year: count}}
cpc_h2_2019 = set()  # CPC groups that appear in H2 2019
cpc_sample_titles = {}  # {cpc_level4: sample_title}

for patent in german_patents:
    patents_info = patent.get('Patents_info', '')
    grant_date = patent.get('grant_date', '')
    cpc = patent.get('cpc', '[]')
    title_localized = patent.get('title_localized', '[]')

    if not grant_date or 'DE-' not in patents_info:
        continue

    year, month = extract_year_month(grant_date)
    if not year or not month:
