    max_ema = 0
    best_year = None

    for year in all_years:
        count = cpc_yearly_counts[cpc_level4].get(year, 0)
        ema = alpha * count + (1 - alpha) * ema
        timeseries[year] = ema

        if ema > max_ema:
            max_ema = ema
            best_year = year

    cpc_ema_results[cpc_level4] = {
        'best_year': best_year,
        'max_ema': max_ema,
        'timeseries': timeseries
    }

# Sort by max EMA
top_results = sorted(cpc_ema_results.items(), key=lambda x: x[1]['max_ema'], reverse=True)

# Format final results
final_results = []
for cpc_level4, data in top_results[:20]:  # Top 20
    final_results.append({
        'cpc_group_code': cpc_level4,
        'full_title': cpc_level4_titles.get(cpc_level4, 'Title not found'),
        'best_year': data['best_year'],
        'max_ema': round(data['max_ema'], 2),
        'sample_patent_title': cpc_sample_titles.get(cpc_level4, 'N/A')
    })

print('__RESULT__:')
print(json.dumps(final_results, indent=2))"}

